// searchResultTitle falls back to a kind label when a hit has no title (chat
// messages, replies and comments are bodies without a subject).
func searchResultTitle(r SearchResultView) string {
	if strings.TrimSpace(r.Title) != "" {
		return r.Title
	}
	switch r.Kind {
	case "chat":
		return "Chat message"
	case "post":
		return "Forum reply"
	case "issue_comment":
		return "Issue comment"
	case "discussion_reply":
		return "Discussion reply"
	case "ai":
		return "Agent message"
	}
	return "Untitled"
}

